// ===== データ整形ノード =====
const body = $input.first().json.body;

// タイムスタンプ → JST変換
const dt = new Date(body.timestamp);
const jst = new Date(dt.getTime() + 9 * 60 * 60 * 1000);
const pad = (n) => String(n).padStart(2, '0');
const timestampJST = `${jst.getUTCFullYear()}/${pad(jst.getUTCMonth()+1)}/${pad(jst.getUTCDate())} ${pad(jst.getUTCHours())}:${pad(jst.getUTCMinutes())}`;

// options の各キーを取り出し（存在しない場合は空文字）
const opts = body.diagnosis.options || {};
const optSetup         = opts['初期セットアップ']          || '';
const optListing       = opts['予約サイトへの掲載']        || '';
const optBeds24        = opts['予約システムの連携設定']    || '';
const optManual        = opts['ハウスマニュアルの作成']    || '';
const optPhoto         = opts['物件写真の撮影']            || '';
const optEvacuation    = opts['避難経路図の作成']          || '';
const optPricing       = opts['宿泊料金の調整']            || '';
const optIdentity      = opts['ゲストの本人確認']          || '';

// recommendedOptions 配列 → カンマ区切り文字列
const recommendedStr = (body.result.recommendedOptions || []).join('、');

// メール本文
const emailBody = `かんたんプラン診断より、新規のお問い合わせがありました。

━━━━━━━━━━━━━━
【お客様情報】
━━━━━━━━━━━━━━
姓　　　：${body.contact.lastName}
名　　　：${body.contact.firstName}
メール　：${body.contact.email}
送信日時：${timestampJST}

━━━━━━━━━━━━━━
【診断回答内容】
━━━━━━━━━━━━━━
${body.summaryText}

---
本メールはn8n自動送信です。`;

return [{
  json: {
    // メール用
    emailSubject: `【かんたんプラン診断】新規お問い合わせ - ${body.contact.lastName} ${body.contact.firstName} 様`,
    emailBody,
    toEmail: 'consulter@bizpato.com',
    // スプレッドシート用
    timestampJST,
    lastName:    body.contact.lastName,
    firstName:   body.contact.firstName,
    email:       body.contact.email,
    formType:    body.diagnosis.formType,
    checkinNeeded: body.diagnosis.checkinNeeded,
    opGuest:     body.diagnosis.operationAnswers.guest,
    opCleaning:  body.diagnosis.operationAnswers.cleaning,
    opReview:    body.diagnosis.operationAnswers.review,
    location:    body.diagnosis.location,
    optSetup,
    optListing,
    optBeds24,
    optManual,
    optPhoto,
    optEvacuation,
    optPricing,
    optIdentity,
    planName:    body.result.planName,
    initialFee:  body.result.initialFee,
    monthlyFee:  body.result.monthlyFee,
    recommendedStr
  }
}];
